import osimport sqlite3import pandas as pddata_path = "/Users/diana/Downloads/dataverse_files"db_name = "airline2.db"def read_csv_safe(file_path):    """    Read CSV with a fallback encoding in case UTF-8 fails.    """    try:        return pd.read_csv(file_path, low_memory=False)    except UnicodeDecodeError:        return pd.read_csv(file_path, encoding="latin1", low_memory=False)if os.path.exists(db_name):    os.remove(db_name)conn = sqlite3.connect(db_name)airports = read_csv_safe(os.path.join(data_path, "airports.csv"))carriers = read_csv_safe(os.path.join(data_path, "carriers.csv"))planes = read_csv_safe(os.path.join(data_path, "plane-data.csv"))airports.to_sql("airports", con=conn, index=False, if_exists="replace")carriers.to_sql("carriers", con=conn, index=False, if_exists="replace")planes.to_sql("planes", con=conn, index=False, if_exists="replace")ontime_2000 = read_csv_safe(os.path.join(data_path, "2000.csv"))ontime_2000.to_sql("ontime", con=conn, index=False, if_exists="replace")for year in range(2001, 2006):    file_name = f"{year}.csv"    file_path = os.path.join(data_path, file_name)    yearly_data = read_csv_safe(file_path)    yearly_data.to_sql("ontime", con=conn, index=False, if_exists="append")    print(f"Added {file_name}")cursor = conn.cursor()tables = cursor.execute("""    SELECT name    FROM sqlite_master    WHERE type='table'""").fetchall()print("Tables in database:")print(tables)for table in ["ontime", "airports", "carriers", "planes"]:    count = cursor.execute(f"SELECT COUNT(*) FROM {table}").fetchone()[0]    print(f"{table}: {count} rows")conn.commit()conn.close()print("airline2.db created successfully.")